+@Suite
+struct PreviewBadgeTests {
+    @Test
+    func formatsBelowOneThousand() {
+        #expect(PreviewMetrics.charCountSuffix(count: 0) == " (0 chars)")
+        #expect(PreviewMetrics.charCountSuffix(count: 999) == " (999 chars)")
+    }
+
+    @Test
